(1, 'Творчество'),
(2, 'Спорт и Фитнес'),
(3, 'Технологии'),
(4, 'Языки'),
(5, 'Кулинария'),
(6, 'Сообщество');
INSERT INTO challenges (id, title, image, description, category_id, difficulty) VALUES
(1, 'Твоя искра в акварели', 'res://art', 'Погрузитесь в мир акварели с нашим интенсивным 7-дневным вызовом! Этот вызов идеально подходит для начинающих и тех, кто хочет освежить свои навыки. Вы научитесь основным техникам, создадите несколько красивых работ и откроете для себя радость спонтанного творчества.', 1, 4),
(2, 'Твоя искра в садоводстве', 'res://plants', 'Откройте для себя радость садоводства! За 7 дней вы научитесь выбирать растения, ухаживать за ними, создавать композиции и даже размножать их. Идеально для новичков, которые хотят добавить природы в свою жизнь. Этот челлендж превратит ваш подоконник или балкон в настоящий оазис.', 6, 4),
(3, 'Твоя искра в Python', 'res://python', 'Хотите научиться программировать? Наш 7-дневный челлендж по Python познакомит вас с основами языка, синтаксисом, переменными, условиями, циклами и функциями. Вы напишете свои первые программы и почувствуете себя настоящим разработчиком! Никаких скучных лекций - только практика.', 3, 2),
(4, 'Твоя искра в йоге', 'res://yoga', 'Йога для начинающих: за 7 дней вы освоите базовые асаны, научитесь правильно дышать и расслабляться. Этот вызов поможет вам улучшить гибкость, снять стресс и почувствовать гармонию тела и разума. Достаточно 20–30 минут в день.', 2, 3),
(5, 'Твоя искра в выпечке', 'res://food', 'Любите сладкое? За 7 дней мы научимся печь простые и вкусные десерты: от печенья до пирогов. Вы узнаете основы работы с тестом, секреты выпечки и создадите свои шедевры. Каждый день - новый рецепт и новые навыки.', 5, 3),
(6, 'Твоя искра в гитаре', 'res://guitar', 'Мечтаете играть на гитаре? За 7 дней вы освоите базовые аккорды, бой, перебор и сыграете свою первую песню. Не нужен музыкальный опыт - только желание! Вы удивитесь, как быстро можно добиться результата.', 1, 2),
(7, 'Твоя искра в мыловарении', 'res://foam', 'Создайте свое уникальное мыло с нуля! За 7 дней вы узнаете основы мыловарения из основы, научитесь работать с цветами, ароматами и формами. Это увлекательное хобби подарит вам полезные и красивые подарки для себя и близких.', 1, 2),
(8, 'Твоя искра в китайском', 'res://china', 'Китайский язык кажется сложным, но с нашим вызовом вы сделаете первые шаги! За 7 дней вы освоите основы произношения (пиньинь), выучите несколько иероглифов и простые фразы, которые помогут в общении. Это интенсивное погружение в язык и культуру.', 4, 4);
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(1, 1, 1, 'День 1: Знакомство с материалами', 'Вы изучите основные материалы: краски, кисти, бумага. Попробуйте сделать несколько мазков и смешивать цвета.'),
(2, 1, 2, 'День 2: Техника "мокрым по мокрому"', 'Техника "мокрым по мокрому" в акварельной живописи заключается в обильном смачивании листа водой с обеих сторон и нанесении красок за один сеанс.'),
(3, 1, 3, 'День 3: Техника "лессировка"', 'Лессировка - техника, при которой несколько тонких слоёв полупрозрачных красок наносятся на основной тон.'),
(4, 1, 4, 'День 4: Работа с текстурой', 'Вы посмотрите, какие завораживающие фактуры создают самые обычные материалы у вас дома! Узнайте, как добиться красивого эффекта.'),
(5, 1, 5, 'День 5: Создание простого пейзажа', 'Наконец-то нарисуем полноценную картину! Практика, практика и еще раз практика!'),
(6, 1, 6, 'День 6: Цветочная открытка. Монотипия', 'Изучим разновидность графического искусства и техники печатной графики с помощью акварели.'),
(7, 1, 7, 'День 7: Финальный проект. Презентация', 'Примените все полученные знания на практике! Оформите работу и поделитесь ею в сообществе.');
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(8, 2, 1, 'День 1: Знакомство с основами', 'Изучите основные факторы роста: свет, вода, температура. Определите, какие растения подходят для ваших условий.'),
(9, 2, 2, 'День 2: Почва и горшки', 'Выберите правильный грунт и ёмкости. Узнайте о дренаже и пересадке.'),
(10, 2, 3, 'День 3: Посадка семян и черенков', 'Посадите свои первые семена или черенки. Создайте мини-парник.'),
(11, 2, 4, 'День 4: Полив и подкормка', 'Разберитесь в режиме полива и первых удобрениях. Научитесь определять, когда растению нужна вода.'),
(12, 2, 5, 'День 5: Формирование композиции', 'Составьте красивую группу из нескольких растений. Играйте с высотой и цветом листвы.'),
(13, 2, 6, 'День 6: Борьба с вредителями', 'Узнайте о типичных вредителях и болезнях. Приготовьте натуральные средства защиты.'),
(14, 2, 7, 'День 7: Финальный проект - мой зелёный уголок', 'Оформите свой сад, сделайте этикетки и поделитесь результатом в сообществе.');
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(15, 3, 1, 'День 1: Установка и первая программа', 'Установите Python и IDE (например, PyCharm или VS Code). Напишите классический "Hello, World!".'),
(16, 3, 2, 'День 2: Переменные и типы данных', 'Узнайте о числах, строках и булевых значениях. Создайте простой калькулятор.'),
(17, 3, 3, 'День 3: Условные операторы', 'Научитесь использовать if, elif, else. Напишите программу, которая отвечает на ввод пользователя.'),
(18, 3, 4, 'День 4: Циклы', 'Освойте циклы for и while. Сгенерируйте таблицу умножения.'),
(19, 3, 5, 'День 5: Функции', 'Создайте свои первые функции. Разбейте код на логические блоки.'),
(20, 3, 6, 'День 6: Строки и списки', 'Работайте со строками и списками. Напишите программу для подсчёта слов.'),
(21, 3, 7, 'День 7: Финальный проект - игра "Угадай число"', 'Соберите все знания в игру: компьютер загадывает число, пользователь угадывает. Поделитесь кодом в сообществе.');
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(22, 4, 1, 'День 1: Дыхание и настрой', 'Изучите диафрагмальное дыхание. Выполните легкую разминку и позу ребенка.'),
(23, 4, 2, 'День 2: Позы стоя', 'Освойте позы горы, воина I и треугольника. Укрепите ноги и спину.'),
(24, 4, 3, 'День 3: Баланс', 'Практикуйте позы дерева и орла. Развивайте координацию.'),
(25, 4, 4, 'День 4: Наклоны и скручивания', 'Выполните наклоны вперёд и скручивания. Улучшите гибкость позвоночника.'),
(26, 4, 5, 'День 5: Прогибы', 'Попробуйте позы кобры и собаки мордой вниз. Раскройте грудную клетку.'),
(27, 4, 6, 'День 6: Силовые позы', 'Планка, чатуранга и поза лодки. Укрепите мышцы кора.'),
(28, 4, 7, 'День 7: Финальная практика и шавасана', 'Соедините все асаны в короткую последовательность. Завершите расслаблением. Поделитесь ощущениями.');
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(29, 5, 1, 'День 1: Сахарное печенье', 'Испеките классическое сахарное печенье. Узнайте, как правильно смешивать ингредиенты.'),
(30, 5, 2, 'День 2: Песочное тесто', 'Приготовьте тарталетки или корзиночки с любой начинкой. Освойте технику "рубленого теста".'),
(31, 5, 3, 'День 3: Бисквит и заварной крем. Классика', 'Испечете простой бисквит на кефире. Узнайте, как сделать его пышным. Приготовим торт с заварным кремом.'),
(32, 5, 4, 'День 4: Дрожжевое тесто', 'Замесите дрожжевое тесто и испеките хлеб или булочки.'),
(33, 5, 5, 'День 5: Заварное тесто', 'Приготовьте профитроли или эклеры. Удивитесь, как это легко!'),
(34, 5, 6, 'День 6: Слоёное тесто', 'Используйте готовое слоёное тесто, чтобы сделать слойки с фруктами или сыром.'),
(35, 5, 7, 'День 7: Финальный проект - торт или пирог', 'Создайте свой фирменный десерт, украсьте его и поделитесь фото.');
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(36, 6, 1, 'День 1: Знакомство с гитарой', 'Узнайте устройство гитары, научитесь её настраивать. Примите правильную посадку.'),
(37, 6, 2, 'День 2: Первые аккорды', 'Выучите аккорды Am, C, G. Потренируйтесь ставить их чисто.'),
(38, 6, 3, 'День 3: Бой', 'Освойте простой бой (вниз-вниз-вверх-вверх-вниз). Пробуйте играть аккорды под бой.'),
(39, 6, 4, 'День 4: Перебор', 'Изучите перебор "четвёрка" (бас-3-2-1). Играйте аккорды перебором.'),
(40, 6, 5, 'День 5: Соединение аккордов', 'Тренируйтесь переставлять аккорды без пауз. Используйте метроном.'),
(41, 6, 6, 'День 6: Разучивание песни', 'Выберите простую песню (например, "Звезда по имени Солнце") и разберите её.'),
(42, 6, 7, 'День 7: Запись и презентация', 'Запишите видео своей игры. Покажите друзьям или в сообществе.');
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(43, 7, 1, 'День 1: Введение и техника безопасности', 'Изучите виды мыльных основ, инструменты и правила безопасности.'),
(44, 7, 2, 'День 2: Первое мыло', 'Растопите основу, залейте в простую форму. Получите готовое мыло.'),
(45, 7, 3, 'День 3: Цвет и аромат', 'Добавьте красители и отдушки. Сделайте мыло с мраморным эффектом.'),
(46, 7, 4, 'День 4: Многослойное мыло', 'Создайте мыло из нескольких слоёв, давая каждому застыть.'),
(47, 7, 5, 'День 5: Мыло с добавками', 'Добавьте в основу овсяные хлопья, кофе или сухие цветы.'),
(48, 7, 6, 'День 6: Мыло с фигурками', 'Поместите внутрь прозрачного мыла маленькую фигурку (трансфер).'),
(49, 7, 7, 'День 7: Упаковка и дизайн', 'Оформите готовое мыло, сделайте этикетки. Подготовьте подарки.');
INSERT INTO weekly_program_days (id, challenge_id, day, title, description) VALUES
(50, 8, 1, 'День 1: Тоны и пиньинь', 'Изучите 4 тона и систему пиньинь. Потренируйтесь произносить слоги.'),
(51, 8, 2, 'День 2: Основные черты и простые иероглифы', 'Научитесь писать базовые иероглифы: 人 (человек), 大 (большой), 小 (маленький).'),
(52, 8, 3, 'День 3: Приветствия', 'Выучите фразы: 你好 (привет), 谢谢 (спасибо), 再见 (до свидания).'),
(53, 8, 4, 'День 4: Числительные 1–10', 'Освойте счёт от 1 до 10. Научитесь считать предметы.'),
(54, 8, 5, 'День 5: Вопросы и ответы', 'Узнайте, как задавать вопросы с 吗. Ответы: 是 (да) и 不 (нет).'),
(55, 8, 6, 'День 6: Еда и напитки', 'Выучите слова: 茶 (чай), 咖啡 (кофе), 面包 (хлеб).'),
(56, 8, 7, 'День 7: Составляем мини-диалог', 'Напишите и разыграйте диалог из нескольких фраз. Запишите видео.');
